select

from test_report_record
where id = #{id,jdbcType=BIGINT}

SELECT id, entrustment_id, report_code, sample_name, required_completion_time, number, issuer_time, seal_type, sealer, seal_time, t2.product_id, qys_docment_id, qys_state, contract_id, sign_url, t1.type reportTypeStatus FROM test_report_record t1 LEFT JOIN test_product t2 ON t1.sample_name = t2.product_name WHERE state =6
AND report_code like CONCAT('%',#{search},'%')
AND qys_state = #{state}
AND report_type = #{reportType}
AND t1.type = #{reportTypeStatus}
order by issuer_time desc

